#include &lt;stdint.h&gt;

// Invented by Dan Bernstein. Uses a magic prime (5381) and bit-shifting 
// to distribute ASCII strings evenly across numeric space.
uint32_t hash_djb2(const char *str) {
    uint32_t hash = 5381;
    int c;
    while ((c = *str++)) {
        // hash = hash * 33 + c; (Optimized to bitshifts by compiler)
        hash = ((hash << 5) + hash) + c; 
    }
    return hash;
}

