#define TABLE_SIZE 1024 // Power of 2 is faster for modulo

typedef struct Node {
    char *key;
    int value;
    struct Node *next;
} Node;

Node *hash_table[TABLE_SIZE] = {NULL}; // Array of Head Pointers

void insert(const char *key, int value) {
    uint32_t index = hash_djb2(key) % TABLE_SIZE;

    // Check for duplicates first
    Node *curr = hash_table[index];
    while (curr) {
        if (strcmp(curr->key, key) == 0) {
            curr->value = value; // Update existing
            return;
        }
        curr = curr->next;
    }

    // Key is new. Prepend to the Head of the collision list O(1)
    Node *new_node = malloc(sizeof(Node));
    new_node->key = strdup(key);
    new_node->value = value;
    new_node->next = hash_table[index];

    hash_table[index] = new_node;
}

