// MUST be a Power of 2 to allow bitwise masking instead of slow modulo
#define RING_SIZE 256 
#define RING_MASK (RING_SIZE - 1)

typedef struct {
    int buffer[RING_SIZE];
    size_t head; // Read index
    size_t tail; // Write index
} RingBuffer;

// Evaluates Full/Empty logic. If head == tail, it's empty.
// If tail is exactly one slot behind head (wrapped), it's full.
bool ring_is_full(RingBuffer *rb) {
    return ((rb->tail + 1) & RING_MASK) == rb->head;
}

bool ring_is_empty(RingBuffer *rb) {
    return rb->head == rb->tail;
}

// The Producer
bool ring_push(RingBuffer *rb, int data) {
    if (ring_is_full(rb)) return false; // Drop packet or Block thread

    rb->buffer[rb->tail] = data;
    rb->tail = (rb->tail + 1) & RING_MASK; // O(1) Wraparound
    return true;
}

// The Consumer
bool ring_pop(RingBuffer *rb, int *out_data) {
    if (ring_is_empty(rb)) return false;

    *out_data = rb->buffer[rb->head];
    rb->head = (rb->head + 1) & RING_MASK; // O(1) Wraparound
    return true;
}

